import React, { useState } from "react";

function AddAssignment({ refresh }) {
  const [title, setTitle] = useState("");
  const [subject, setSubject] = useState("");
  const [dueDate, setDueDate] = useState("");
  const [message, setMessage] = useState("");

  const handleSubmit = async (e) => {
    e.preventDefault();
    setMessage("");

    try {
      const res = await fetch("http://localhost:8080/assignments/add/1", {
        method: "POST",
        headers: {"Content-Type": "application/json"},
        body: JSON.stringify({ title, subject, dueDate })
      });

      if (!res.ok) throw new Error("Failed to save assignment");

      setMessage("Assignment added successfully!");
      setTitle("");
      setSubject("");
      setDueDate("");
      refresh();
    } catch (err) {
      setMessage(err.message);
    }
  };

  return (
    <div>
      <h2>Add Assignment</h2>
      {message && <p>{message}</p>}
      <form onSubmit={handleSubmit}>
        <input value={title} onChange={e=>setTitle(e.target.value)} placeholder="Title" required /><br/><br/>
        <input value={subject} onChange={e=>setSubject(e.target.value)} placeholder="Subject" required /><br/><br/>
        <input type="date" value={dueDate} onChange={e=>setDueDate(e.target.value)} required /><br/><br/>
        <button>Add Assignment</button>
      </form>
    </div>
  );
}

export default AddAssignment;
